        // ── Story Mode: Point detail ──
        let _selectedIdx = -1;

        function _isDesktop() { return window.innerWidth > 1024; }
        function _isTablet() { return window.innerWidth >= 768 && window.innerWidth <= 1024; }

        function _buildDetailHTML(p) {
            var isDesktopView = _isDesktop();
            let h = '<div style="padding:4px 0;">';

            if (p.image_url && !isDesktopView) {
                // Tablet/Mobile: image covers full height of ALL text, no background block
                h += '<div style="display:flex;gap:12px;align-items:stretch;">';
                h += '<img src="' + p.image_url + '" class="story-detail-img" style="width:130px;object-fit:cover;flex-shrink:0;cursor:pointer;display:block;border-radius:6px;border:1px solid rgba(138,117,76,0.2);" />';
                h += '<div style="flex:1;min-width:0;display:flex;flex-direction:column;justify-content:center;">';
                h += '<div style="font-family:Crimson Pro,serif;font-size:15px;font-weight:600;color:#e8e6e3;margin-bottom:3px;">' + esc(p.name) + '</div>';
                if (p.date_text || p.date) {
                    h += '<div style="font-size:10px;color:#d4af37;font-weight:600;margin-bottom:3px;display:flex;align-items:center;gap:3px;">';
                    h += '<span class="material-symbols-outlined" style="font-size:12px;">calendar_today</span>';
                    h += esc(p.date_text || p.date) + '</div>';
                }
                if (typeof PERIODS !== 'undefined' && p.period_id) {
                    var period = PERIODS.find(function(pr) { return pr.id === p.period_id; });
                    if (period) {
                        h += '<div style="font-size:9px;color:' + (period.color || '#d4af37') + ';font-weight:600;margin-bottom:3px;display:flex;align-items:center;gap:3px;text-transform:uppercase;letter-spacing:0.05em;">';
                        h += '<span class="material-symbols-outlined" style="font-size:11px;">date_range</span>';
                        h += esc(period.name) + '</div>';
                    }
                }
                if (p.description) {
                    h += '<div style="font-size:11px;color:#a8a4a0;line-height:1.5;margin-bottom:3px;">' + esc(p.description) + '</div>';
                }
                // Place & location INSIDE the flex card
                if (p.place) {
                    h += '<div style="font-size:10px;color:#6e6863;display:flex;align-items:center;gap:3px;margin-bottom:2px;">';
                    h += '<span class="material-symbols-outlined" style="font-size:12px;color:#8a754c;">pin_drop</span>';
                    h += esc(p.place) + '</div>';
                }
                var _loc = [p.region, p.country].filter(Boolean).join(', ');
                if (_loc) {
                    h += '<div style="font-size:10px;color:#6e6863;display:flex;align-items:center;gap:3px;">';
                    h += '<span class="material-symbols-outlined" style="font-size:12px;color:#8a754c;">public</span>';
                    h += esc(_loc) + '</div>';
                }
                h += '</div></div>';
                // Skip the common place/loc/category block below
                h += '</div>';
                return h;
            } else {
                // Desktop or no image: vertical layout
                h += '<div style="font-family:Crimson Pro,serif;font-size:18px;font-weight:600;color:#e8e6e3;margin-bottom:6px;">' + esc(p.name) + '</div>';
                if (p.date_text || p.date) {
                    h += '<div style="font-size:11px;color:#d4af37;font-weight:600;margin-bottom:8px;display:flex;align-items:center;gap:4px;">';
                    h += '<span class="material-symbols-outlined" style="font-size:13px;">calendar_today</span>';
                    h += esc(p.date_text || p.date) + '</div>';
                }
                if (typeof PERIODS !== 'undefined' && p.period_id) {
                    var period = PERIODS.find(function(pr) { return pr.id === p.period_id; });
                    if (period) {
                        h += '<div style="font-size:10px;color:' + (period.color || '#d4af37') + ';font-weight:600;margin-bottom:6px;display:flex;align-items:center;gap:4px;text-transform:uppercase;letter-spacing:0.05em;">';
                        h += '<span class="material-symbols-outlined" style="font-size:12px;">date_range</span>';
                        h += esc(period.name) + '</div>';
                    }
                }
                if (p.image_url) {
                    h += '<div style="position:relative;margin-bottom:8px;cursor:pointer;" class="story-detail-img-wrap">';
                    h += '<img src="' + p.image_url + '" class="story-detail-img" style="width:100%;height:auto;border-radius:6px;border:1px solid rgba(138,117,76,0.2);" />';
                    h += '<div style="position:absolute;top:6px;right:6px;width:24px;height:24px;border-radius:50%;background:rgba(26,22,20,0.8);display:flex;align-items:center;justify-content:center;">';
                    h += '<span class="material-symbols-outlined" style="font-size:14px;color:#d4af37;">zoom_in</span></div>';
                    h += '</div>';
                }
                if (p.description) {
                    h += '<div style="font-size:12px;color:#a8a4a0;line-height:1.6;margin-bottom:10px;">' + esc(p.description) + '</div>';
                }
            }
            if (p.place) {
                h += '<div style="font-size:11px;color:#6e6863;display:flex;align-items:center;gap:4px;margin-bottom:4px;">';
                h += '<span class="material-symbols-outlined" style="font-size:13px;color:#8a754c;">pin_drop</span>';
                h += esc(p.place) + '</div>';
            }
            const loc = [p.region, p.country].filter(Boolean).join(', ');
            if (loc) {
                h += '<div style="font-size:11px;color:#6e6863;display:flex;align-items:center;gap:4px;margin-bottom:4px;">';
                h += '<span class="material-symbols-outlined" style="font-size:13px;color:#8a754c;">public</span>';
                h += esc(loc) + '</div>';
            }
            if (p.category && p.category !== 'default') {
                h += '<div style="margin-top:8px;">';
                h += '<span style="display:inline-flex;align-items:center;gap:3px;background:#151210;border:1px solid rgba(138,117,76,0.2);border-radius:4px;padding:3px 8px;font-size:10px;color:#a8a4a0;">';
                h += '<span class="material-symbols-outlined" style="font-size:12px;color:' + (p.color || '#d4af37') + ';">' + catIcon(p.category) + '</span>';
                h += catLabel(p.category) + '</span></div>';
            }
            h += '</div>';
            return h;
        }

        function openStoryLightbox(imgUrl) {
            var existing = document.querySelector('.story-img-lightbox');
            if (existing) existing.remove();
            var lb = document.createElement('div');
            lb.className = 'story-img-lightbox';
            lb.onclick = function(e) { if (e.target === lb) lb.remove(); };
            var lbImg = document.createElement('img');
            lbImg.src = imgUrl;
            lbImg.onclick = function(e) { e.stopPropagation(); };
            lb.appendChild(lbImg);
            var closeBtn = document.createElement('button');
            closeBtn.className = 'lb-close';
            closeBtn.innerHTML = '<span class="material-symbols-outlined">close</span>';
            closeBtn.onclick = function() { lb.remove(); };
            lb.appendChild(closeBtn);
            document.body.appendChild(lb);
            document.addEventListener('keydown', function handler(e) {
                if (e.key === 'Escape') { lb.remove(); document.removeEventListener('keydown', handler); }
            });
        }

        // Delegate clicks on detail images to open lightbox
        document.addEventListener('click', function(e) {
            var img = e.target.closest('.story-detail-img') || (e.target.closest('.story-detail-img-wrap') ? e.target.closest('.story-detail-img-wrap').querySelector('img') : null);
            if (img && img.src) openStoryLightbox(img.src);
        });

        function _clearSelection() {
            // Remove marker pulse from previous
            if (_selectedIdx >= 0 && pointMarkers[_selectedIdx]) {
                const el = pointMarkers[_selectedIdx].getElement();
                if (el) { const pin = el.querySelector('.terra-marker-pin'); if (pin) pin.classList.remove('selected-marker'); }
            }
            // Remove dot pulse
            document.querySelectorAll('.story-tl-dot.active').forEach(d => d.classList.remove('active'));
            // Remove sp-item highlight
            document.querySelectorAll('.sp-item.sp-item-selected').forEach(el => el.classList.remove('sp-item-selected'));
        }

        function _highlightSelection(idx) {
            // Pulse marker pin
            if (pointMarkers[idx]) {
                const el = pointMarkers[idx].getElement();
                if (el) { const pin = el.querySelector('.terra-marker-pin'); if (pin) pin.classList.add('selected-marker'); }
            }
            // Pulse timeline dot
            const dots = document.querySelectorAll('.story-tl-dot');
            let dotIdx = 0;
            POINTS.forEach((p, i) => {
                if (p.date_start || p.date) {
                    if (i === idx && dots[dotIdx]) dots[dotIdx].classList.add('active');
                    dotIdx++;
                }
            });
            // Highlight side panel item
            document.querySelectorAll('.sp-item').forEach(function(el) {
                const onclick = el.getAttribute('onclick') || '';
                if (onclick.indexOf('flyToPoint(' + idx + ')') !== -1) {
                    el.classList.add('sp-item-selected');
                }
            });
        }

        function showPointDetail(idx) {
            const p = POINTS[idx];
            if (!p) return;

            _clearSelection();
            _selectedIdx = idx;

            const m = pointMarkers[idx];
            if (m) map.flyTo(m.getLatLng(), Math.max(map.getZoom(), 12), { duration: 0.8 });

            // Highlight after a short delay (marker element may not exist yet after flyTo)
            setTimeout(() => _highlightSelection(idx), 100);

            if (_isDesktop()) {
                // Desktop: right detail panel
                const detail = document.getElementById('sdp-detail');
                if (detail) detail.innerHTML = _buildDetailHTML(p);
            } else {
                // Tablet & Mobile: floating card at bottom
                const card = document.getElementById('story-mobile-detail');
                const body = document.getElementById('smd-body');
                if (card && body) {
                    body.innerHTML = _buildDetailHTML(p);
                    card.classList.add('visible');
                }
            }
        }

        function closeMobileDetail() {
            const card = document.getElementById('story-mobile-detail');
            if (card) card.classList.remove('visible');
            _clearSelection();
            _selectedIdx = -1;
        }

        // Handle tablet→desktop resize: hide mobile detail card, show desktop panel
        window.addEventListener('resize', function() {
            if (_isDesktop()) {
                var card = document.getElementById('story-mobile-detail');
                if (card) card.classList.remove('visible');
                if (_selectedIdx >= 0) showPointDetail(_selectedIdx);
            }
        });
        

        // ── Regions (polygons) ──
        const regionLayers = [];
        REGIONS.forEach(r => {
            if (!r.coordinates || !r.coordinates.length) return;
            const poly = L.polygon(r.coordinates, {
                color: r.color || '#d4af37', weight: 2, opacity: r.stroke_opacity || 0.8,
                fillColor: r.color || '#d4af37', fillOpacity: r.fill_opacity || 0.25,
            });
            let popup = '<div class="popup-title">' + esc(r.name) + '</div>';
            if (r.description) popup += '<div class="popup-desc">' + esc(r.description) + '</div>';
            poly.bindPopup(popup).addTo(map);
            regionLayers.push(poly);
        });

        // ── Routes (polylines) ──
        const routeLayers = [];
        ROUTES.forEach(r => {
            const coords = (r.route_geometry && r.route_geometry.length) ? r.route_geometry : r.waypoints;
            if (!coords || !coords.length) return;
            const line = L.polyline(coords, {
                color: r.color || '#3b82f6', weight: 3, opacity: 0.8, dashArray: '8,6',
            });
            let popup = '<div class="popup-title">' + esc(r.name) + '</div>';
            if (r.distance_km) popup += '<div class="popup-desc">' + r.distance_km.toFixed(1) + ' km &middot; ' + Math.round(r.duration_min) + ' min</div>';
            if (r.description) popup += '<div class="popup-desc">' + esc(r.description) + '</div>';
            line.bindPopup(popup).addTo(map);
            routeLayers.push(line);
        });

        // ── Fit bounds ──
        const allBounds = [];
        POINTS.forEach(p => allBounds.push([p.lat, p.lng]));
        REGIONS.forEach(r => (r.coordinates || []).forEach(c => allBounds.push(c)));
        ROUTES.forEach(r => {
            const coords = (r.route_geometry && r.route_geometry.length) ? r.route_geometry : r.waypoints;
            (coords || []).forEach(c => allBounds.push(c));
        });
        if (allBounds.length > 0) {
            map.fitBounds(L.latLngBounds(allBounds).pad(0.1));
        }

        // ── Navigation helpers ──
        function flyToPoint(idx) {
            const m = pointMarkers[idx];
            if (!m) return;
            map.flyTo(m.getLatLng(), 12, { duration: 0.8 });
            
            showPointDetail(idx);
            
        }
        function flyToRegion(idx) {
            const l = regionLayers[idx];
            if (l) { map.flyToBounds(l.getBounds().pad(0.1), { duration: 0.8 }); l.openPopup(); }
        }
        function flyToRoute(idx) {
            const l = routeLayers[idx];
            if (l) { map.flyToBounds(l.getBounds().pad(0.1), { duration: 0.8 }); l.openPopup(); }
        }

        // ── Side Panel: search, grouping, rebuild ──
        
        const collapsedGroups = {};

        function clearSearch() {
            const input = document.getElementById('sp-search');
            if (input) input.value = '';
            document.getElementById('sp-search-clear').style.display = 'none';
            rebuildPanel();
        }

        document.getElementById('sp-search')?.addEventListener('input', function() {
            document.getElementById('sp-search-clear').style.display = this.value ? 'block' : 'none';
            rebuildPanel();
        });

        function toggleGroup(key) {
            collapsedGroups[key] = !collapsedGroups[key];
            rebuildPanel();
        }

        function rebuildPanel() {
            const body = document.getElementById('sp-body');
            if (!body) return;

            const searchTerm = normalize(document.getElementById('sp-search')?.value || '');
            const groupBy = document.getElementById('sp-group-by')?.value || 'category';

            let html = '';

            // Filter points
            let filtered = POINTS.map((p, idx) => ({ ...p, _idx: idx }));
            if (searchTerm) {
                filtered = filtered.filter(p =>
                    normalize(p.name).includes(searchTerm)
                    || normalize(p.description).includes(searchTerm)
                    || normalize(p.region).includes(searchTerm)
                    || normalize(p.country).includes(searchTerm)
                    || normalize(p.category).includes(searchTerm)
                    || normalize(catLabel(p.category)).includes(searchTerm)
                );
            }

            if (searchTerm) {
                html += '<div class="sp-filter-info">' + filtered.length + ' de ' + POINTS.length + ' puntos</div>';
            }

            // Sort (story mode)
            
            const sortBy = document.getElementById('sp-sort-by')?.value || 'date';
            if (sortBy === 'date') {
                filtered.sort((a, b) => {
                    const da = a.date_start || a.date || '';
                    const db = b.date_start || b.date || '';
                    if (!da && !db) return 0;
                    if (!da) return 1;
                    if (!db) return -1;
                    return da.localeCompare(db);
                });
            } else if (sortBy === 'name') {
                filtered.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
            }
            // 'original' keeps the original POINTS order (no sort needed)
            

            // Group
            const groups = {};
            filtered.forEach(p => {
                let key;
                if (groupBy === 'category') key = p.category || 'default';
                else if (groupBy === 'country') key = p.country || 'Sin pais';
                else if (groupBy === 'region') key = p.region || 'Sin region';
                else if (groupBy === 'period') {
                    if (typeof PERIODS !== 'undefined' && p.period_id) {
                        const period = PERIODS.find(pr => pr.id === p.period_id);
                        key = period ? period.name : 'Sin periodo';
                    } else { key = 'Sin periodo'; }
                } else if (groupBy === 'date') {
                    const ds = p.date_start || p.date || '';
                    const yearMatch = ds.match(/^-?(\d{1,4})/);
                    key = yearMatch ? (ds.startsWith('-') ? yearMatch[1] + ' a.C.' : yearMatch[1]) : 'Sin fecha';
                }
                else key = '__all__';
                if (!groups[key]) groups[key] = [];
                groups[key].push(p);
            });

            const sortedKeys = Object.keys(groups).sort((a, b) => {
                if (a === '__all__') return 0;
                if (groupBy === 'date') {
                    // Sort chronologically
                    if (a === 'Sin fecha') return 1;
                    if (b === 'Sin fecha') return -1;
                    const aNum = a.includes('a.C.') ? -parseInt(a) : parseInt(a);
                    const bNum = b.includes('a.C.') ? -parseInt(b) : parseInt(b);
                    return aNum - bNum;
                }
                return a.toLowerCase() < b.toLowerCase() ? -1 : 1;
            });

            for (const key of sortedKeys) {
                const pts = groups[key];
                const isCollapsed = !!collapsedGroups[key];
                const label = (key === '__all__') ? 'Todos' : (groupBy === 'category' ? catLabel(key) : key);
                const icon = groupBy === 'category' ? catIcon(key) : (groupBy === 'country' ? 'public' : (groupBy === 'period' ? 'date_range' : (groupBy === 'date' ? 'calendar_today' : 'map')));

                html += '<div class="sp-section">';
                html += '<div class="sp-section-title" onclick="toggleGroup(\'' + key.replace(/'/g, "\\'") + '\')">';
                html += '<span class="material-symbols-outlined" style="font-size:13px;color:#d4af37;">' + icon + '</span>';
                html += '<span style="flex:1;">' + esc(label) + '</span>';
                html += '<span class="sp-count">' + pts.length + '</span>';
                html += '<span class="material-symbols-outlined sp-arrow' + (isCollapsed ? ' collapsed' : '') + '">expand_more</span>';
                html += '</div>';

                if (!isCollapsed) {
                    pts.forEach(p => {
                        const sub = [p.region, p.country].filter(Boolean).join(', ');
                        
                        const dateInfo = p.date_text || p.date || '';
                        const subLine = [dateInfo, sub].filter(Boolean).join(' · ');
                        html += '<div class="sp-item" onclick="flyToPoint(' + p._idx + ')">';
                        if (p.image_url) {
                            html += '<img class="sp-item-img" src="' + esc(p.image_url) + '" alt="" />';
                        }
                        html += '<div class="sp-dot" style="background:' + (p.color || '#d4af37') + ';"></div>';
                        html += '<div style="flex:1;min-width:0;"><div class="sp-item-name">' + esc(p.name) + '</div>';
                        if (subLine) html += '<div class="sp-item-sub">' + esc(subLine) + '</div>';
                        html += '</div></div>';
                        
                    });
                }
                html += '</div>';
            }

            // Regions (filtered by search too)
            let filteredRegions = REGIONS.map((r, i) => ({ ...r, _idx: i }));
            if (searchTerm) {
                filteredRegions = filteredRegions.filter(r =>
                    normalize(r.name).includes(searchTerm) || normalize(r.description).includes(searchTerm)
                );
            }
            if (filteredRegions.length) {
                html += '<div class="sp-section">';
                html += '<div class="sp-section-title" onclick="toggleGroup(\'__regions__\')">';
                html += '<span class="material-symbols-outlined" style="font-size:13px;color:#d4af37;">pentagon</span>';
                html += '<span style="flex:1;">Regiones</span>';
                html += '<span class="sp-count">' + filteredRegions.length + '</span>';
                html += '<span class="material-symbols-outlined sp-arrow' + (collapsedGroups['__regions__'] ? ' collapsed' : '') + '">expand_more</span>';
                html += '</div>';
                if (!collapsedGroups['__regions__']) {
                    filteredRegions.forEach(r => {
                        html += '<div class="sp-item" onclick="flyToRegion(' + r._idx + ')">';
                        html += '<div class="sp-dot" style="background:' + (r.color || '#d4af37') + ';"></div>';
                        html += '<div><div class="sp-item-name">' + esc(r.name) + '</div>';
                        if (r.description) html += '<div class="sp-item-sub">' + esc(r.description).substring(0, 60) + '</div>';
                        html += '</div></div>';
                    });
                }
                html += '</div>';
            }

            // Routes (filtered by search too)
            let filteredRoutes = ROUTES.map((r, i) => ({ ...r, _idx: i }));
            if (searchTerm) {
                filteredRoutes = filteredRoutes.filter(r =>
                    normalize(r.name).includes(searchTerm) || normalize(r.description).includes(searchTerm)
                );
            }
            if (filteredRoutes.length) {
                html += '<div class="sp-section">';
                html += '<div class="sp-section-title" onclick="toggleGroup(\'__routes__\')">';
                html += '<span class="material-symbols-outlined" style="font-size:13px;color:#3b82f6;">route</span>';
                html += '<span style="flex:1;">Rutas</span>';
                html += '<span class="sp-count">' + filteredRoutes.length + '</span>';
                html += '<span class="material-symbols-outlined sp-arrow' + (collapsedGroups['__routes__'] ? ' collapsed' : '') + '">expand_more</span>';
                html += '</div>';
                if (!collapsedGroups['__routes__']) {
                    filteredRoutes.forEach(r => {
                        const dist = r.distance_km ? (r.distance_km.toFixed(1) + ' km') : '';
                        html += '<div class="sp-item" onclick="flyToRoute(' + r._idx + ')">';
                        html += '<div class="sp-dot" style="background:' + (r.color || '#3b82f6') + ';"></div>';
                        html += '<div><div class="sp-item-name">' + esc(r.name) + '</div>';
                        if (dist) html += '<div class="sp-item-sub">' + dist + '</div>';
                        html += '</div></div>';
                    });
                }
                html += '</div>';
            }

            // Empty state
            if (!filtered.length && !filteredRegions.length && !filteredRoutes.length) {
                html += '<div style="text-align:center;padding:24px 0;color:#6e6863;font-size:11px;">';
                html += '<span class="material-symbols-outlined" style="font-size:24px;display:block;margin-bottom:4px;">search_off</span>';
                html += 'Sin resultados</div>';
            }

            body.innerHTML = html;
        }

        // Initial build
        rebuildPanel();
        

        // ── Stats (optional, collapsible, matches app layout) ──
        

        
        // ── Story Timeline Bar ──
        (function() {
            function parseDate(s) {
                if (!s || typeof s !== 'string') return null;
                s = s.trim();
                if (/^-?\d{1,4}-\d{2}(-\d{2})?$/.test(s)) {
                    var parts = s.split('-');
                    if (s.startsWith('-')) { var d = new Date(0); d.setFullYear(-parseInt(parts[1]),parseInt(parts[2])-1,parseInt(parts[3])||1); return d; }
                    var d = new Date(0); d.setFullYear(parseInt(parts[0]),parseInt(parts[1])-1,parts[2]?parseInt(parts[2]):1); return d;
                }
                if (/^-?\d{1,4}$/.test(s)) { var d = new Date(0); d.setFullYear(parseInt(s),0,1); return d; }
                return null;
            }
            function fmtYear(d) { if (!d) return ''; var y = d.getFullYear(); return y < 0 ? Math.abs(y)+' a.C.' : ''+y; }

            var allDates = [];
            POINTS.forEach(function(p) { var d = parseDate(p.date_start || p.date); if (d) allDates.push(d.getTime()); });
            if (allDates.length < 2) return;

            var minT = Math.min.apply(null, allDates), maxT = Math.max.apply(null, allDates);
            var pad = (maxT - minT) * 0.02 || 365*24*3600*1000;
            minT -= pad; maxT += pad;
            var range = maxT - minT;

            function toPos(t) { return (t - minT) / range; }

            // Range label
            document.getElementById('stl-range').textContent = fmtYear(new Date(minT + pad)) + ' — ' + fmtYear(new Date(maxT - pad));

            // Date labels
            var labelsEl = document.getElementById('stl-labels');
            for (var i = 0; i < 5; i++) {
                var p = i / 4;
                var lbl = document.createElement('span');
                lbl.className = 'story-tl-label';
                lbl.style.left = (p * 100) + '%';
                lbl.textContent = fmtYear(new Date(minT + range * p));
                labelsEl.appendChild(lbl);
            }

            // Dots
            var dotsEl = document.getElementById('stl-dots');
            POINTS.forEach(function(p, idx) {
                var d = parseDate(p.date_start || p.date);
                if (!d) return;
                var pos = toPos(d.getTime());
                if (pos < 0 || pos > 1) return;
                var dot = document.createElement('div');
                dot.className = 'story-tl-dot';
                dot.style.left = (pos * 100) + '%';
                dot.style.backgroundColor = p.color || '#d4af37';
                dot.title = p.name + (p.date_text ? ' (' + p.date_text + ')' : '');
                dot.addEventListener('click', function() {
                    showPointDetail(idx);
                });
                dotsEl.appendChild(dot);
            });

            // Periods as compact colored lines with label on dark background
            if (typeof PERIODS !== 'undefined') {
                var periodsEl = document.getElementById('stl-periods');
                var totalPeriods = PERIODS.length;
                PERIODS.forEach(function(period, lineIdx) {
                    var dStart = parseDate(period.date_start);
                    var dEnd = parseDate(period.date_end);
                    if (!dStart && !dEnd) return;
                    var posStart = dStart ? toPos(dStart.getTime()) : 0;
                    var posEnd = dEnd ? toPos(dEnd.getTime()) : 1;
                    var left = Math.max(0, Math.min(posStart, posEnd));
                    var right = Math.min(1, Math.max(posStart, posEnd));
                    var color = period.color || '#d4af37';
                    var widthPct = (right - left) * 100;

                    // Stack well below center line (50%): first at 65%, then 78%, 91%
                    var topPct = 65 + (lineIdx * 13);

                    // Main colored line
                    var line = document.createElement('div');
                    line.style.cssText = 'position:absolute;left:' + (left * 100) + '%;width:' + widthPct + '%;height:4px;top:' + topPct + '%;background:' + color + ';opacity:0.85;pointer-events:none;border-radius:2px;';
                    periodsEl.appendChild(line);

                    // Text label centered ON the line with dark background that "cuts" through
                    if (widthPct > 3 && period.name) {
                        var lbl = document.createElement('span');
                        lbl.style.cssText = 'position:absolute;left:' + (left * 100) + '%;width:' + widthPct + '%;top:calc(' + topPct + '% - 6px);height:16px;display:flex;align-items:center;justify-content:center;pointer-events:none;z-index:2;';
                        var inner = document.createElement('span');
                        inner.style.cssText = 'background:rgba(26,22,20,0.9);padding:1px 6px;border-radius:2px;font-size:8px;color:' + color + ';white-space:nowrap;overflow:hidden;text-overflow:ellipsis;text-transform:uppercase;letter-spacing:0.06em;font-weight:700;max-width:100%;';
                        inner.textContent = period.name;
                        lbl.appendChild(inner);
                        periodsEl.appendChild(lbl);
                    }
                    line.title = period.name;
                });
            }
        })();